import { _decorator, Component, director, Node, Button, Label } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('LoginScene')
export class LoginScene extends Component {
    @property(Button)
    loginBtn: Button = null;
    
    @property(Label)
    titleLabel: Label = null;
    
    onLoad() {
        if (this.loginBtn) {
            this.loginBtn.node.on(Button.EventType.CLICK, this.onLogin, this);
        }
        
        if (this.titleLabel) {
            this.titleLabel.string = '财神大陆 - 点击登录';
        }
    }
    
    async onLogin() {
        console.log('开始登录...');
        
        // 测试账号直接登录
        const phone = '13800138001';
        const code = '1234';
        
        try {
            const result = await GameManager.getInstance().network.request('/api/auth/login', {
                phone: phone,
                code: code
            });
            
            console.log('登录结果:', result);
            
            if (result.success) {
                GameManager.getInstance().playerData.setToken(result.token);
                GameManager.getInstance().playerData.setUserInfo(result.user);
                
                if (this.titleLabel) {
                    this.titleLabel.string = '登录成功！';
                }
                
                // 2秒后进入主场景
                setTimeout(() => {
                    director.loadScene('MainScene');
                }, 1000);
            } else {
                if (this.titleLabel) {
                    this.titleLabel.string = '登录失败:' + result.message;
                }
            }
        } catch (error) {
            console.error('登录错误:', error);
            if (this.titleLabel) {
                this.titleLabel.string = '网络错误';
            }
        }
    }
}
